styles:
.page-header {
      background: white;
      padding: 8rem 0 4rem;
      text-align: center;
      border-bottom: 1px solid var(--border);
    }
    .page-header h1 {
      font-size: clamp(2rem, 5vw, 3rem);
      margin-bottom: 1rem;
      color: var(--text-primary);
    }
    .page-header p {
      color: var(--text-secondary);
      font-size: 1.125rem;
    }
    .page-content {
      background: white;
      padding: 4rem 0;
    }
    .page-content .container {
      max-width: 800px;
    }
    .contact-grid {
      display: grid;
      grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
      gap: 2rem;
      margin-bottom: 3rem;
    }
    .contact-card {
      background: var(--bg-secondary);
      padding: 2rem;
      border-radius: var(--radius-lg);
      text-align: center;
    }
    .contact-card h3 {
      font-size: 1.125rem;
      margin-bottom: 0.5rem;
      color: var(--text-primary);
    }
    .contact-card p {
      color: var(--text-secondary);
      margin-bottom: 1rem;
    }
    .contact-card a {
      color: var(--primary);
      font-weight: 500;
    }
    .contact-card a:hover {
      text-decoration: underline;
    }
    .contact-form-section h2 {
      font-size: 1.5rem;
      margin-bottom: 1rem;
      color: var(--text-primary);
    }
    .contact-form-section > p {
      color: var(--text-secondary);
      margin-bottom: 2rem;
      line-height: 1.6;
    }
    .contact-form {
      background: var(--bg-secondary);
      padding: 2rem;
      border-radius: var(--radius-lg);
    }
    .form-group {
      margin-bottom: 1.5rem;
    }
    .form-group label {
      display: block;
      font-weight: 500;
      margin-bottom: 0.5rem;
      color: var(--text-primary);
    }
    .form-group input,
    .form-group textarea,
    .form-group select {
      width: 100%;
      padding: 0.875rem 1rem;
      border: 1px solid var(--border);
      border-radius: var(--radius);
      font-size: 1rem;
      font-family: inherit;
      background: white;
      color: var(--text-primary);
      transition: border-color 0.2s, box-shadow 0.2s;
    }
    .form-group input:focus,
    .form-group textarea:focus,
    .form-group select:focus {
      outline: none;
      border-color: var(--primary);
      box-shadow: 0 0 0 3px rgba(79, 70, 229, 0.1);
    }
    .form-group textarea {
      min-height: 150px;
      resize: vertical;
    }
    .form-row {
      display: grid;
      grid-template-columns: 1fr 1fr;
      gap: 1rem;
    }
    .submit-btn {
      display: inline-flex;
      align-items: center;
      gap: 0.5rem;
      padding: 1rem 2rem;
      background: var(--primary);
      color: white;
      border: none;
      border-radius: var(--radius);
      font-size: 1rem;
      font-weight: 500;
      cursor: pointer;
      transition: background 0.2s;
    }
    .submit-btn:hover {
      background: var(--primary-dark);
    }
    .response-time {
      background: var(--bg-secondary);
      padding: 2rem;
      border-radius: var(--radius-lg);
      margin-top: 3rem;
      text-align: center;
    }
    .response-time h3 {
      font-size: 1.25rem;
      margin-bottom: 0.5rem;
      color: var(--text-primary);
    }
    .response-time p {
      color: var(--text-secondary);
    }
    @media (max-width: 768px) {
      .page-header {
        padding: 6rem 0 3rem;
      }
      .page-content {
        padding: 3rem 0;
      }
      .form-row {
        grid-template-columns: 1fr;
      }
    }
